# update_pd_routing.py — update PagerDuty routing rules for Day-2
import requests, os

PD_API_KEY = os.environ["PAGERDUTY_API_KEY"]
HEADERS = {
    "Authorization": f"Token token={PD_API_KEY}",
    "Content-Type": "application/json",
    "Accept": "application/vnd.pagerduty+json;version=2",
}

def create_routing_rule(service_id: str, condition: str, escalation_policy_id: str):
    """Add alert routing rule for Claude API v2 alerts."""
    rule = {
        "routing_rule": {
            "conditions": [
                {"expression": condition}
            ],
            "actions": [
                {
                    "type": "route",
                    "value": service_id,
                    "escalation_policy": {"id": escalation_policy_id, "type": "escalation_policy_reference"}
                }
            ]
        }
    }
    r = requests.post(
        "https://api.pagerduty.com/routing_rules",
        json=rule, headers=HEADERS
    )
    r.raise_for_status()
    print(f"Routing rule created: {r.json()['routing_rule']['id']}")

# Route claude-gateway alerts to SRE team escalation policy
create_routing_rule(
    service_id="PSRVE01",
    condition='event.summary matches "claude-gateway"',
    escalation_policy_id="EP_SRE_PROD"
)

# Route safety eval alerts to safety team
create_routing_rule(
    service_id="PSRVE02",
    condition='event.summary matches "claude.*eval.*regression"',
    escalation_policy_id="EP_SAFETY_TEAM"
)
